    'Microsoft.Extensions.Logging': '10.0.7',
    'Microsoft.Extensions.Hosting': '10.0.7',
    'OpenTelemetry.Extensions.Hosting': '1.15.3',
}

# TFM-specific updates
tfm_updates = {
    ('Microsoft.AspNetCore.Mvc.NewtonsoftJson', 'net8.0'): '8.0.26',
}

for project in data['projects']:
    for fw in project['frameworks']:
        for pkg in fw['topLevelPackages']:
            key = (pkg['id'], fw['framework'])
            if key in tfm_updates:
                pkg['requestedVersion'] = tfm_updates[key]
                pkg['resolvedVersion'] = tfm_updates[key]
            elif pkg['id'] in updates:
                pkg['requestedVersion'] = updates[pkg['id']]
                pkg['resolvedVersion'] = updates[pkg['id']]

with open('baseline-packages.json', 'w') as f:
    json.dump(data, f, indent=2)
    f.write('\n')
print('Done')
